protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
        // Preserve the old name so EF9 can read existing documents without a data migration.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id generation from "EntityType|KeyValue" (e.g. "Product|123")
        // to just the key value ("123"). Existing documents use the compound format.
        // Preserve the old format so FindAsync and point-reads work against existing data.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // Removed: HasIndex(p => p.Sku)
    // EF Core 9 Cosmos provider now throws on HasIndex — Cosmos DB indexing
    // is managed via the container's indexing policy (Azure Portal / Bicep / Terraform).
}

